module top_module(
   input                      clk,
   input                      rst,
   output                     done,
   input                      rq_vld_in,
   input                      rs_vld_in
);reg   [63:0]               invalid_rq_count;
   reg   [63:0]               rs_count_s;

   always @(posedge clk)
   begin
      if (rst == 1)              invalid_rq_count <= 64'd0;
      else if (rq_vld_in == 1)   invalid_rq_count <= invalid_rq_count + 64'd1;

      if (rst == 1)              rs_count_s <= 64'd0;
      else if (rs_vld_in == 1)   rs_count_s <= rs_count_s + 64'd1;

   end

   assign done = (invalid_rq_count == rs_count_s);

endmodule
